#include <stdio.h>

long long fac[250005];

int main()
{
    int n, m;
    long long ans = 0;
    scanf("%d%d", &n, &m);

    fac[0] = 1;
    for(int i = 1; i <= n; i++){
        fac[i] = (fac[i - 1] * i) % m;
    }

    for(int i = 0; i < n; i++){
        ans += (fac[i + 1] * fac[n - i]) % m;
        ans %= m;
    }

    ans = (ans * (n + 1)) % m;
    if(ans % 2 == 1) ans = (ans + m) / 2;
    else ans /= 2;

    printf("%I64d", ans);
    return 0;
}

